import { createSlice } from '@reduxjs/toolkit'
import axios from 'axios'


export const userLoginSlice = createSlice({
    name: 'userLogin',
    initialState: {},
    reducers: {
        userLoginRequest: (state, action) => {
            state.loading = true;
        },

        userLoginSucces: (state, action) => { 
            state.loading = false;
            state.userInfo = action.payload; 
        },

        userLoginFail: (state, action) => { 
           state.loading = false; 
            state.error = action.payload;
        },

        userLogout: (state, action) => { 
          
        },
    }
})
export const { userLoginRequest, userLoginSucces, userLoginFail, userLogout } = userLoginSlice.actions
export default userLoginSlice.reducer;


// thunk functions to login a user

export const login = (email, password) => async (dispatch) => {
    try{
        dispatch(userLoginRequest())

        const config = {
            headers:{
                'content-type':'application/json'
            }
        }

        const { data } = await axios.post(
            'api/users/login/',
            { 'username': email,  'password':password },
            config
            )

        dispatch(userLoginSucces(data))

        localStorage.setItem('userInfo', JSON.stringify(data))
        
    } catch (error) {
        const msg = (error.response && error.response.data.message ? error.response.data.message : error.message)
        dispatch(userLoginFail(msg))
    }
}
